package format

import (
	"bytes"
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter produces a condensed, summary-style diff output
// for terraform plan, showing only resource-level changes without
// attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a string representation of the plan changes in a compact format.
// It shows one line per resource change and groups changes by action type.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	var buf bytes.Buffer

	// Group changes by action
	changes := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, resource := range plan.Changes.Resources {
		if resource.DeposedKey == "" { // Only include current objects, not deposed ones
			changes[resource.Action] = append(changes[resource.Action], resource)
		}
	}

	// Define the order of actions for consistent output
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.CreateThenForget,
		plans.Forget,
		plans.Read,
		plans.NoOp,
	}

	// Output changes grouped by action
	for _, action := range actionOrder {
		resources, ok := changes[action]
		if !ok || len(resources) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})

		// Print action group header
		switch action {
		case plans.Create:
			buf.WriteString("# Create:\n")
		case plans.Update:
			buf.WriteString("# Update:\n")
		case plans.Delete:
			buf.WriteString("# Delete:\n")
		case plans.DeleteThenCreate:
			buf.WriteString("# Replace (delete then create):\n")
		case plans.CreateThenDelete:
			buf.WriteString("# Replace (create then delete):\n")
		case plans.CreateThenForget:
			buf.WriteString("# Create then forget:\n")
		case plans.Forget:
			buf.WriteString("# Forget:\n")
		case plans.Read:
			buf.WriteString("# Read:\n")
		case plans.NoOp:
			buf.WriteString("# No changes:\n")
		}

		// Print each resource
		for _, resource := range resources {
			actionSymbol := actionSymbolCompact(action)
			buf.WriteString(fmt.Sprintf("  %s %s\n", actionSymbol, resource.Addr.String()))
		}

		buf.WriteString("\n")
	}

	// Print summary
	counts := make(map[plans.Action]int)
	for action, resources := range changes {
		counts[action] = len(resources)
	}

	summary := formatSummary(counts)
	if summary != "" {
		buf.WriteString(summary)
	}

	return buf.String()
}

// actionSymbolCompact returns a short symbol for each action type
func actionSymbolCompact(action plans.Action) string {
	switch action {
	case plans.Create:
		return "+"
	case plans.Update:
		return "~"
	case plans.Delete:
		return "-"
	case plans.DeleteThenCreate:
		return "±"
	case plans.CreateThenDelete:
		return "∓"
	case plans.CreateThenForget:
		return "⨥"
	case plans.Forget:
		return "."
	case plans.Read:
		return "<="
	case plans.NoOp:
		return " "
	default:
		return "?"
	}
}

// formatSummary returns a summary line with change counts
func formatSummary(counts map[plans.Action]int) string {
	if len(counts) == 0 {
		return ""
	}

	creates := counts[plans.Create]
	updates := counts[plans.Update]
	deletes := counts[plans.Delete]
	replaces := counts[plans.DeleteThenCreate] + counts[plans.CreateThenDelete]
	reads := counts[plans.Read]
	forgets := counts[plans.Forget] + counts[plans.CreateThenForget]

	// Only show non-zero counts
	var parts []string
	if creates > 0 {
		parts = append(parts, fmt.Sprintf("%d to add", creates))
	}
	if updates > 0 {
		parts = append(parts, fmt.Sprintf("%d to change", updates))
	}
	if replaces > 0 {
		parts = append(parts, fmt.Sprintf("%d to replace", replaces))
	}
	if deletes > 0 {
		parts = append(parts, fmt.Sprintf("%d to delete", deletes))
	}
	if reads > 0 {
		parts = append(parts, fmt.Sprintf("%d to read", reads))
	}
	if forgets > 0 {
		parts = append(parts, fmt.Sprintf("%d to forget", forgets))
	}

	if len(parts) == 0 {
		return ""
	}

	return fmt.Sprintf("Plan: %s\n", strings.Join(parts, ", "))
}

